actions.script:
import org.moqui.adk.AdkManager
import org.moqui.adk.AdkSessionHolder

// Lazy-init: session service + all enabled agent configs
if (!AdkManager.isInitialized()) {
    AdkManager.lazyInit(ec.factory)
}

if (!AdkManager.isInitialized()) {
    ec.message.addError('ADK not configured — add API key in ADK → Configuration')
    return
}

Map contextState = [
    userId          : ec.user.userId   ?: 'anonymous',
    username        : ec.user.username ?: 'anonymous',
    userFullName    : '',
    organizationName: '',
    companyPseudoId : '',
    tenantId        : 'DEFAULT',
    timeZone        : ec.user.timeZone?.ID ?: 'UTC',
    locale          : ec.user.locale?.toString() ?: 'en_US',
]
try {
    boolean wasDisabled = ec.artifactExecution.disableAuthz()
    try {
        def userAcct = ec.entity.find('moqui.security.UserAccount')
            .condition('userId', ec.user.userId)
            .selectField('userFullName').selectField('partyId')
            .one()
        contextState.userFullName = userAcct?.userFullName ?: ''

        String userPartyId = userAcct?.partyId
        if (userPartyId) {
            def userParty = ec.entity.find('mantle.party.Party')
                .condition('partyId', userPartyId)
                .selectField('ownerPartyId').one()
            String ownerPartyId = userParty?.ownerPartyId
            if (ownerPartyId) {
                contextState.tenantId = ownerPartyId

                // Load githubToken from SystemSettings into system property
                // so GithubTool.resolveGithubToken() can find it without a compile.
                if (!System.getenv('GITHUB_TOKEN')) {
                    def ss = ec.entity.find('growerp.general.SystemSettings')
                        .condition('ownerPartyId', ownerPartyId).one()
                    if (ss?.githubToken) {
                        System.setProperty('growerp.github.token', ss.githubToken)
                    }
                    if (ss?.githubRepository) {
                        System.setProperty('growerp.github.repo', ss.githubRepository)
                    }
                }

                def companyList = ec.entity.find('mantle.party.PartyDetailAndRole')
                    .condition('ownerPartyId', ownerPartyId)
                    .condition('partyTypeEnumId', 'PtyOrganization')
                    .condition('roleTypeId', 'OrgInternal')
                    .limit(1).list()
                String companyPartyId = companyList[0]?.partyId
                if (companyPartyId) {
                    def org = ec.entity.find('mantle.party.Organization')
                        .condition('partyId', companyPartyId).one()
                    contextState.organizationName = org?.organizationName ?: ''

                    def companyParty = ec.entity.find('mantle.party.Party')
                        .condition('partyId', companyPartyId)
                        .selectField('pseudoId').one()
                    contextState.companyPseudoId = companyParty?.pseudoId ?: ''
                }
            }
        }
    } finally { if (!wasDisabled) ec.artifactExecution.enableAuthz() }
} catch (Exception ignored) { /* best-effort */ }

def adkSession = AdkManager.createSession(ec.user.userId ?: 'anonymous', contextState)
sessionId = adkSession.id as String

import org.moqui.adk.AdkManager
import org.moqui.adk.AdkSessionHolder

if (!AdkManager.isInitialized()) {
    AdkManager.lazyInit(ec.factory)
}

if (!AdkManager.isInitialized()) {
    response = '[Error: ADK not configured — add API key in ADK → Configuration]'
    return
}

AdkSessionHolder.logEvent(sessionId, 'user_message', 'User message', [message: message])

String runUserId = ec.user.userId ?: 'anonymous'
def events = AdkManager.runAgent(runUserId, sessionId, message)

// Event author is the AGENT NAME (not 'model'); the echoed user prompt
// has author == runUserId. Collect text from all non-partial agent events.
StringBuilder sb = new StringBuilder()
events.each { e ->
    if (e.author != runUserId && e.partial != true) {
        e.content?.parts?.each { p -> if (p.text) sb.append(p.text) }
    }
}
response = sb.toString().trim()
if (!response) {
    def lastText = events.reverse().find { e ->
        e.author != runUserId && e.content?.parts?.find { it.text }
    }
    response = (lastText?.content?.parts?.findResults { it.text }?.join('') ?: '').trim()
}

if (!response) response = '[No response from agent]'
AdkSessionHolder.logEvent(sessionId, 'agent_response', 'Agent replied', [response: response])
